class Solution:
    def getLargestOutlier(self, nums):
        n = len(nums)
        total = sum(nums)
        best = None
        for i in range(n):
            for j in range(n):
                if i == j:
                    continue
                if total - 2 * nums[i] == nums[j]:
                    if best is None or nums[j] > best:
                        best = nums[j]
        return best

