from collections import Counter
class Solution:
    def getLargestOutlier(self, nums):
        count = Counter(nums)
        total = sum(nums)
        best = None
        for x in count:
            candidate = total - 2 * x
            if candidate in count:
                if candidate != x or count[x] > 1:
                    if best is None or candidate > best:
                        best = candidate
        return best

