var getLargestOutlier = function(nums) {
    const count = new Map();
    let total = 0;
    for (const x of nums) {
        total += x;
        count.set(x, (count.get(x) || 0) + 1);
    }
    let best = null;
    for (const x of count.keys()) {
        const candidate = total - 2 * x;
        if (count.has(candidate)) {
            if (candidate !== x || count.get(x) > 1) {
                if (best === null || candidate > best) best = candidate;
            }
        }
    }
    return best;
};
